    }
    if (strchr(level_str, ' ') == NULL) {
        printf("PROBE: Malformed input (no number)\n");
        return;
    }

    level = atoi(level_str);

    const char *act_pos = strchr(uart_line, 'PUMP');
    if (act_pos == NULL) {
        printf("PROBE: Malformed output\n");
        return;
    }
    act_pos++;
    while (*act_pos && !(*act_pos == ' ' || *act_pos == '\t')) {
        act_pos++;
    }
    if (strchr(act_pos, ' ') == NULL) {
        printf("PROBE: Malformed output\n");
        return;
    }

    const char *on_pos = strchr(act_pos + strlen(act_pos), 'ON');
    if (on_pos == NULL) {
        printf("PROBE: Malformed output\n");
        return;
    }
    on_pos++;
    while (*on_pos && !(*on_pos == '\n' || *on_pos == '\r')) {
        on_pos++;
    }

    const char *action = strchr(on_pos, ' ');
    if (action == NULL) {
        printf("PROBE: Malformed output\n");
        return;
    }
    *action = '\0';

    /* Simulate the step function */
    controller_output_t result = controller_step(NULL, {
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = level,
        .now_ms = 0U,
    });

    printf("PROBE: Input=SENSE LEVEL %d, Output=%s\n", level, result.state_name);
}

