#include <stdio.h>
#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->pump_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_level = 0;
    controller->last_valid_sensor_ms = 0U;
}

void controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .pump_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_pump_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_pump_on = controller->pump_on;
    previous_state = controller->state;

    /* Implement the task-specific control policy here. */
    switch (input.kind) {
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_sensor = true;
        controller->last_level = input.level;
        controller->last_valid_sensor_ms = input.now_ms;
        if (input.level < CONTROLLER_LEVEL_LOW_THRESHOLD) {
            controller_set_safe_off(controller);
        } else if (input.level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
            controller_set_safe_off(controller);
        } else {
            /* Mid-band: hold the previous safe output */
            controller->pump_on = previous_pump_on;
            controller->state = previous_state;
            controller->changed = false;
        }
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        controller_set_safe_off(controller);
        break;
    }

    output.pump_on = controller->pump_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_pump_on != controller->pump_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_PUMPING:
        return "STATE PUMPING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

/* Firmware-level end-to-end runtime probe through UART */
void controller_firmware_probe(controller_t *controller, const char *uart_line)
{
    /* Parse the incoming line from UART */
    int level = 0;
    char *newline_pos = strchr(uart_line, '\n');
    if (newline_pos == NULL) {
        return; /* No newline means malformed input */
    }
    *newline_pos = '\0';

    /* Parse the line: "SENSE LEVEL <n>" */
    const char *line_start = uart_line;
    while (*line_start && !(*line_start == ' ' || *line_start == '\t')) {
        line_start++;
    }
    if (strchr(line_start, ' ') == NULL) {
        /* No space after level */
        return; /* Malformed input */
    }

    const char *level_str = line_start + strlen(line_start);
    while (*level_str && !(*level_str == ' ' || *level_str == '\t')) {
        level_str++;
    }
    if (strchr(level_str, ' ') == NULL) {
        /* No number */
        return; /* Malformed input */
    }

    level = atoi(level_str);

    /* Parse: "ACT PUMP ON" or "ACT PUMP OFF" */
    const char *act_pos = strchr(uart_line, 'PUMP');
    if (act_pos == NULL) {
        return; /* Malformed output */
    }
    act_pos++;
    while (*act_pos && !(*act_pos == ' ' || *act_pos == '\t')) {
        act_pos++;
    }
    if (strchr(act_pos, ' ') == NULL) {
        /* No space after pump */
        return; /* Malformed output */
    }

    const char *on_pos = strchr(act_pos + strlen(act_pos), 'ON');
    if (on_pos == NULL) {
        return; /* Malformed output */
    }
    on_pos++;
    while (*on_pos && !(*on_pos == '\n' || *on_pos == '\r')) {
        on_pos++;
    }

    /* Parse the action: ON or OFF */
    const char *action = strchr(on_pos, ' ');
    if (action == NULL) {
        return; /* Malformed output */
    }
    *action = '\0';

    /* Store the parsed input for the probe function */
    controller_probe_input_t probe_input = {
        .kind = CONTROLLER_INPUT_NONE,
        .level = level,
        .now_ms = 0U,
    };

    /* Call step with the parsed input to verify behavior */
    controller_output_t result = controller_step(controller, probe_input);

    /* Verify that the expected output was produced */
    if (strcmp(action, "ON") == 0) {
        /* Expected: pump should be ON when low level */
        if (result.pump_on != true) {
            printf("FAIL: Expected ACT PUMP ON but got %s\n", result.state_name);
            return;
        }
    } else if (strcmp(action, "OFF") == 0) {
        /* Expected: pump should be OFF when high level */
        if (result.pump_on != false) {
            printf("FAIL: Expected ACT PUMP OFF but got %s\n", result.state_name);
            return;
        }
    } else {
        printf("FAIL: Unexpected action '%s'\n", action);
        return;
    }

    printf("PASS: Firmware probe for level=%d, output=%s\n", level, result.state_name);
}

/* Helper function to send a probe through UART */
void controller_send_probe(controller_t *controller, const char *uart_line)
{
    /* This would normally be called from QEMU's UART driver */
    /* For now we just log what the expected behavior should be */
    printf("Probe sent: %s -> Expected pump=%s\n", uart_line, result ? "ON" : "OFF");
}

