            printf("FAIL: Expected ACT PUMP OFF but got %s\n", result.state_name);
            return;
        }
    } else {
        printf("FAIL: Unexpected action '%s'\n", action);
        return;
    }

    printf("PASS: Firmware probe for level=%d, output=%s\n", level, result.state_name);
}

