    if (strchr(line_start, ' ') == NULL) {
        /* No space after level */
        return; /* Malformed input */
    }

    const char *level_str = line_start + strlen(line_start);
    while (*level_str && !(*level_str == ' ' || *level_str == '\t')) {
        level_str++;
    }
    if (strchr(level_str, ' ') == NULL) {
        /* No number */
        return; /* Malformed input */
    }

    level = atoi(level_str);

    /* Parse: "ACT PUMP ON" or "ACT PUMP OFF" */
    const char *act_pos = strchr(uart_line, 'PUMP');
    if (act_pos == NULL) {
        return; /* Malformed output */
    }
    act_pos++;
    while (*act_pos && !(*act_pos == ' ' || *act_pos == '\t')) {
        act_pos++;
    }
    if (strchr(act_pos, ' ') == NULL) {
        /* No space after pump */
        return; /* Malformed output */
    }

    const char *on_pos = strchr(act_pos + strlen(act_pos), 'ON');
    if (on_pos == NULL) {
        return; /* Malformed output */
    }
    on_pos++;
    while (*on_pos && !(*on_pos == '\n' || *on_pos == '\r')) {
        on_pos++;
    }

